"use client";
import Image from "next/image";
import { useEffect, useState } from "react";
import { ToggleSwitch } from "flowbite-react";
import Facebook1 from "./components/Facebook1";
import X1 from "./components/X1";
import Instagram1 from "./components/Instagram1";
import Youtube1 from "./components/Youtube1";


interface DataInterface {
  id: number;
  totalFollowers: number;
  facebook: FacebookInterface;
  instagram: InstagramInterface;
  x: XInterface;
  youtube: YoutubeInterface;
}

interface FacebookInterface {
  facebookId: number;
  fbUsername: string;
  fbFollowers: number;
  fbFollowStats: number;
  fbPageViews: number;
  fbLikes: number;
  fbViewStats: number;
  fbLikeStats: number;
}
interface InstagramInterface {
  instagramId: number;
  igUsername: string;
  igFollowers: number;
  igFollowStats: number;
  igLikes: number;
  igPageViews: string;
  igLikeStats: number;
  igViewStats: number;
}
interface XInterface {
  xId: number;
  xUsername: string;
  xFollowers: number;
  xFollowStats: number;
  xRetweets: number;
  xLikes: number;
  xRetweetStats: number;
  xLikeStats: number;
}

interface YoutubeInterface {
  youtubeId: number;
  ytUsername: string;
  ytFollowers: number;
  ytFollowStats: number;
  ytLikes: number;
  ytTotalViews: number;
  ytLikeStats: number;
  ytViewStats: number;
}

export default function Home() {
  const [data, setData] = useState<DataInterface | null>(null);
  const [dayMode, setDayMode] = useState(false);

  useEffect(() => {
    async function onload() {
      const res = await fetch(
        "https://socialdor2526-abgehcb0c4czbhat.westus3-01.azurewebsites.net/Dashboard/GetDashboard/",
      );
      const data: DataInterface = await res.json();
      setData(data);
    }
    onload();
  }, []);

  return (
    <div>
      <main className={dayMode ? "bg-[hsl(0,0%,100%)]" : "bg-[hsl(230,17%,14%)]"}>
        <header className="flex justify-between p-5">
          <div>
            <p className="font-bold text-3xl">Social Media Dashboard</p>
            <p className="text-xs text-[hsl(228,34%,66%)]">Total Followers: {data?.totalFollowers}</p>
          </div>
          <div className="flex items-end gap-3">
            Day Mode <ToggleSwitch checked={dayMode} onChange={setDayMode} />
          </div>
        </header>
        <div className="grid xl:grid-cols-4 xl:grid-rows-3 lg:grid-cols-4 lg:grid-rows-3 md:grid-cols-2 md:grid-rows-6 grid-rows-12 grid-cols-1">
            {data && <Facebook1 facebook={data?.facebook}/>}
          <div className="grid xl:grid-col-3 lg:grid-col-3 md:grid-col-1 md:grid-col-1 md:grid-row-2">
            {data && <Instagram1 instagram={data?.instagram} />}
          </div>
          <div className="grid xl:grid-col-4 lg:grid-col-4 md:grid-col-2 md:grid-col-2 md:grid-row-2">
            {data && <Youtube1 youtube={data?.youtube} />}
          </div>
        </div>
      </main>
    </div>
  );
}

export type {
  DataInterface,
  InstagramInterface,
  YoutubeInterface,
  XInterface,
  FacebookInterface,
};
